const mrr = inputs.mrr;
const gm = inputs.gross_margin / 100;
const churn = inputs.churn_rate / 100;
const spend = inputs.total_spend;
const users = inputs.new_customers;

if (!users || users <= 0) return { cac: 0, ltv: 0, ratio: 0, payback: 0 };

const cac = spend / users;
const ltv = (mrr * gm) / Math.max(churn, 0.0001);
const ratio = ltv / Math.max(cac, 0.01);
const payback = cac / Math.max(mrr * gm, 0.01);

return { cac, ltv, ratio, payback };
